{"content": "\"\"\"\nSam Vapi Phone Agent \u2014 NetSuite Webhook Server\nFlask server that handles tool calls from Sam (Vapi AI phone agent) during live calls.\n\nEndpoints:\n  POST /lookup_order     \u2014 Look up a sales order by order number or customer email\n  POST /create_case      \u2014 Create a NetSuite support case from a phone call\n  POST /lookup_customer  \u2014 Find customer + recent cases/orders by email or phone\n  GET  /health           \u2014 Health check\n\nVapi sends:\n  {\n    \"message\": {\n      \"type\": \"tool-calls\",\n      \"toolCallList\": [{\n        \"id\": \"call_xxx\",\n        \"name\": \"lookup_order\",\n        \"arguments\": {\"order_number\": \"SORB-12345\"}\n      }]\n    }\n  }\n\nVapi expects back:\n  {\n    \"results\": [{\n      \"toolCallId\": \"call_xxx\",\n      \"result\": \"plain English string Sam will speak\"\n    }]\n  }\n\"\"\"\n\nimport hmac\nimport hashlib\nimport base64\nimport time\nimport random\nimport string\nimport urllib.parse\nimport requests\nimport json\nimport re\nfrom flask import Flask, request, jsonify\nfrom datetime import datetime\n\napp = Flask(__name__)\n\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# NetSuite credentials & URLs\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nNS_CONSUMER_KEY    = '62dcb9b1151f4ce47301b73765b8438874992d57d0ca57fa05f78aa994e14ba0'\nNS_CONSUMER_SECRET = '35f728cf6037c3b422df23233765e2418441f82cba98e90d4bc18ac4b9197cb7'\nNS_TOKEN_ID        = '19d53555407d9ef6b531720869dd543602fe157e823672a1b368e93215b19223'\nNS_TOKEN_SECRET    = '89f33464075517f514ccfa2ed30e69afd14acc005efeac595ad235cbbd26e7eb'\nNS_REALM           = '5108296'\n\nBASE_URL    = 'https://5108296.suitetalk.api.netsuite.com/services/rest/record/v1'\nSUITEQL_URL = 'https://5108296.suitetalk.api.netsuite.com/services/rest/query/v1/suiteql'\n\n# Defaults for new cases\nCASE_PROFILE_ID    = '2'       # Rambo Bikes profile\nCASE_COMPANY_ID    = '202230'  # Anonymous Rambo (fallback when customer not found)\nCASE_PRIORITY_ID   = '2'       # Medium\nCASE_SUBSIDIARY_ID = '14'      # Rambo Bikes\nCASE_ORIGIN_PHONE  = '2'       # Phone\nAI_EMPLOYEE_ID     = '2718778' # Rambo AI CS agent\n\n# Order status readable labels\nORDER_STATUS_MAP = {\n    'A': 'pending approval',\n    'B': 'pending fulfillment (not yet shipped)',\n    'C': 'billed',\n    'D': 'pending delivery',\n    'G': 'shipped and billed',\n    'H': 'cancelled',\n}\n\n\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# OAuth 1.0 helper\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndef make_auth_header(method, url, extra_params=None):\n    \"\"\"Generate OAuth 1.0 HMAC-SHA256 Authorization header for NetSuite.\"\"\"\n    nonce     = ''.join(random.choices(string.ascii_letters + string.digits, k=32))\n    timestamp = str(int(time.time()))\n\n    oauth_params = {\n        'oauth_consumer_key':     NS_CONSUMER_KEY,\n        'oauth_nonce':            nonce,\n        'oauth_signature_method': 'HMAC-SHA256',\n        'oauth_timestamp':        timestamp,\n        'oauth_token':            NS_TOKEN_ID,\n        'oauth_version':          '1.0',\n    }\n\n    all_params = {**oauth_params}\n    if extra_params:\n        all_params.update(extra_params)\n\n    sorted_params = '&'.join([\n        f'{urllib.parse.quote(k, safe=\"\")}={urllib.parse.quote(str(v), safe=\"\")}'\n        for k, v in sorted(all_params.items())\n    ])\n    base_string  = f'{method.upper()}&{urllib.parse.quote(url, safe=\"\")}&{urllib.parse.quote(sorted_params, safe=\"\")}'\n    signing_key  = f'{urllib.parse.quote(NS_CONSUMER_SECRET, safe=\"\")}&{urllib.parse.quote(NS_TOKEN_SECRET, safe=\"\")}'\n    signature    = base64.b64encode(\n        hmac.new(signing_key.encode(), base_string.encode(), hashlib.sha256).digest()\n    ).decode()\n\n    oauth_params['oauth_signature'] = signature\n    auth_header = (\n        f'OAuth realm=\"{NS_REALM}\",'\n        + ','.join([\n            f'{k}=\"{urllib.parse.quote(str(v), safe=\"\")}\"'\n            for k, v in oauth_params.items()\n        ])\n    )\n    return auth_header\n\n\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# NetSuite helpers\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndef run_suiteql(query):\n    \"\"\"Run a SuiteQL query and return the items list or [] on error.\"\"\"\n    auth    = make_auth_header('POST', SUITEQL_URL)\n    headers = {\n        'Authorization': auth,\n        'Content-Type':  'application/json',\n        'Prefer':        'transient',\n    }\n    try:\n        resp = requests.post(SUITEQL_URL, headers=headers, json={'q': query}, timeout=15)\n        if resp.status_code == 200:\n            return resp.json().get('items', [])\n        else:\n            app.logger.error(f'SuiteQL error {resp.status_code}: {resp.text[:400]}')\n            return []\n    except Exception as e:\n        app.logger.error(f'SuiteQL exception: {e}')\n        return []\n\n\ndef get_rec(record_type, record_id):\n    \"\"\"Fetch a single NetSuite record by type + id.\"\"\"\n    url  = f'{BASE_URL}/{record_type}/{record_id}'\n    auth = make_auth_header('GET', url)\n    headers = {'Authorization': auth, 'Content-Type': 'application/json'}\n    try:\n        resp = requests.get(url, headers=headers, timeout=15)\n        if resp.status_code == 200:\n            return resp.json()\n        else:\n            app.logger.error(f'GET {record_type}/{record_id} error {resp.status_code}: {resp.text[:300]}')\n            return None\n    except Exception as e:\n        app.logger.error(f'GET exception: {e}')\n        return None\n\n\ndef post_rec(record_type, payload):\n    \"\"\"POST a new NetSuite record. Returns (record_id, None) or (None, error_str).\"\"\"\n    url  = f'{BASE_URL}/{record_type}'\n    auth = make_auth_header('POST', url)\n    headers = {'Authorization': auth, 'Content-Type': 'application/json'}\n    try:\n        resp = requests.post(url, headers=headers, json=payload, timeout=15)\n        if resp.status_code in (200, 201, 204):\n            location = resp.headers.get('Location', '')\n            # Location: .../supportcase/12345678\n            match = re.search(r'/(\\d+)$', location)\n            record_id = match.group(1) if match else None\n            return record_id, None\n        else:\n            return None, resp.text[:400]\n    except Exception as e:\n        return None, str(e)\n\n\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# Business logic helpers\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndef format_date(date_str):\n    \"\"\"Convert '6/3/2025' or '2025-06-03' \u2192 'June 3rd, 2025'.\"\"\"\n    if not date_str:\n        return None\n    try:\n        # Try M/D/YYYY\n        dt = None\n        for fmt in ('%m/%d/%Y', '%Y-%m-%d', '%Y-%m-%dT%H:%M:%SZ'):\n            try:\n                dt = datetime.strptime(date_str, fmt)\n                break\n            except ValueError:\n                continue\n        if not dt:\n            return date_str\n        day = dt.day\n        suffix = 'th' if 11 <= day <= 13 else {1: 'st', 2: 'nd', 3: 'rd'}.get(day % 10, 'th')\n        return dt.strftime(f'%B %-d{suffix}, %Y')\n    except Exception:\n        return date_str\n\n\ndef normalize_phone(phone):\n    \"\"\"Strip all non-digits from a phone number.\"\"\"\n    return re.sub(r'\\D', '', phone or '')\n\n\ndef find_customer_by_email(email):\n    \"\"\"Returns first matching customer row or None.\"\"\"\n    rows = run_suiteql(f\"\"\"\n        SELECT id, firstname, lastname, email, phone\n        FROM customer\n        WHERE LOWER(email) = LOWER('{email.replace(\"'\", \"''\")}')\n        AND ROWNUM <= 1\n    \"\"\")\n    return rows[0] if rows else None\n\n\ndef find_customer_by_phone(phone):\n    \"\"\"Search customers by phone (tries multiple formats).\"\"\"\n    digits = normalize_phone(phone)\n    if not digits:\n        return None\n    # Try common formats\n    formats = []\n    if len(digits) == 10:\n        formats = [\n            f'({digits[:3]}) {digits[3:6]}-{digits[6:]}',\n            f'{digits[:3]}-{digits[3:6]}-{digits[6:]}',\n            f'{digits[:3]}.{digits[3:6]}.{digits[6:]}',\n            digits,\n        ]\n    else:\n        formats = [digits]\n\n    for fmt in formats:\n        rows = run_suiteql(f\"\"\"\n            SELECT id, firstname, lastname, email, phone\n            FROM customer\n            WHERE phone = '{fmt.replace(\"'\", \"''\")}'\n            AND ROWNUM <= 1\n        \"\"\")\n        if rows:\n            return rows[0]\n    return None\n\n\ndef get_order_summary(order_id):\n    \"\"\"Fetch full order record and return a human-readable summary string.\"\"\"\n    rec = get_rec('salesOrder', order_id)\n    if not rec:\n        return None\n\n    tran_id  = rec.get('tranId', '?')\n    status   = rec.get('status', {})\n    status_id = status.get('id', '') if isinstance(status, dict) else str(status)\n    status_label = ORDER_STATUS_MAP.get(status_id, f'status {status_id}')\n\n    ship_date   = rec.get('shipDate') or rec.get('actualShipDate')\n    tracking    = rec.get('linkedTrackingNumbers', '')\n    ship_addr   = rec.get('shippingAddress_text', '') or rec.get('shipAddress', '')\n\n    parts = [f'Order {tran_id} is currently {status_label}.']\n\n    if status_id == 'B':\n        parts.append('It has not shipped yet.')\n    elif status_id in ('G', 'C', 'D'):\n        if ship_date:\n            parts.append(f'It shipped on {format_date(ship_date)}.')\n        if tracking:\n            # Could be multiple, space-separated\n            tracking_list = tracking.strip().split()\n            if len(tracking_list) == 1:\n                parts.append(f'The tracking number is {tracking}.')\n            else:\n                parts.append(f'Tracking numbers: {\", \".join(tracking_list)}.')\n        else:\n            parts.append('No tracking number is on file yet.')\n    elif status_id == 'A':\n        parts.append('It is waiting for approval before processing.')\n    elif status_id == 'H':\n        parts.append('This order has been cancelled.')\n\n    if ship_addr:\n        # Compact the address to one line for reading aloud\n        addr_oneline = ', '.join(line.strip() for line in ship_addr.strip().splitlines() if line.strip())\n        parts.append(f'Ship-to address: {addr_oneline}.')\n\n    return ' '.join(parts)\n\n\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# Vapi request parsing\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndef parse_vapi_request(data):\n    \"\"\"\n    Extract (tool_call_id, tool_name, arguments) from a Vapi tool-call payload.\n    Handles both payload formats:\n      - NEW (server-url tools): message.toolCalls[].{id, type, function.{name, arguments}}\n      - OLD (legacy):           message.toolCallList[].{id, name, arguments}\n    Returns list of (call_id, name, args) tuples.\n    \"\"\"\n    calls = []\n    message = data.get('message', {})\n    # NEW format: message.toolCalls (Vapi server-url tool format)\n    tool_calls_new = message.get('toolCalls', [])\n    for tc in tool_calls_new:\n        call_id  = tc.get('id', '')\n        fn       = tc.get('function', {})\n        name     = fn.get('name', '')\n        args     = fn.get('arguments', {})\n        if isinstance(args, str):\n            try:\n                args = json.loads(args)\n            except Exception:\n                args = {}\n        calls.append((call_id, name, args))\n\n    # OLD format: message.toolCallList (legacy)\n    if not calls:\n        tool_call_list = message.get('toolCallList', [])\n        for tc in tool_call_list:\n            call_id = tc.get('id', '')\n            name    = tc.get('name', '')\n            args    = tc.get('arguments', {})\n            if isinstance(args, str):\n                try:\n                    args = json.loads(args)\n                except Exception:\n                    args = {}\n            calls.append((call_id, name, args))\n\n    return calls\n\n\ndef vapi_response(call_id, result_text):\n    \"\"\"Wrap a result string in Vapi's expected response format.\"\"\"\n    return jsonify({'results': [{'toolCallId': call_id, 'result': result_text}]})\n\n\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# Endpoints\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n@app.route('/health', methods=['GET'])\ndef health():\n    return jsonify({'status': 'ok', 'service': 'sam-netsuite-tools', 'timestamp': datetime.utcnow().isoformat()})\n\n\n@app.route('/lookup_order', methods=['POST'])\ndef lookup_order():\n    \"\"\"\n    Look up a Rambo Bikes sales order by:\n      - order_number (e.g. 'SORB-12345')\n      - customer_email\n    Returns a plain-English string Sam can read to the caller.\n    \"\"\"\n    data  = request.get_json(force=True, silent=True) or {}\n    calls = parse_vapi_request(data)\n\n    # Support direct JSON call (for testing) as well as Vapi format\n    if not calls:\n        call_id = data.get('tool_call_id', 'direct')\n        args    = data.get('parameters', data.get('arguments', data))\n        calls   = [(call_id, 'lookup_order', args)]\n\n    call_id, _, args = calls[0]\n\n    order_number   = (args.get('order_number') or '').strip().upper()\n    customer_email = (args.get('customer_email') or '').strip().lower()\n\n    try:\n        if order_number:\n            # \u2500\u2500 Look up by order number \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n            rows = run_suiteql(f\"\"\"\n                SELECT id, tranid, status, trandate, shipdate\n                FROM transaction\n                WHERE tranid = '{order_number.replace(\"'\", \"''\")}'\n                  AND recordtype = 'salesorder'\n                AND ROWNUM <= 1\n            \"\"\")\n            if not rows:\n                return vapi_response(call_id,\n                    f\"I wasn't able to find an order with the number {order_number}. \"\n                    \"Could you double-check the order number? It usually starts with SORB dash followed by numbers.\"\n                )\n            row    = rows[0]\n            result = get_order_summary(row['id'])\n            return vapi_response(call_id, result or f'I found order {order_number} but could not retrieve the details. Please hold while I transfer you.')\n\n        elif customer_email:\n            # \u2500\u2500 Look up most recent order by customer email \u2500\u2500\u2500\u2500\u2500\u2500\n            rows = run_suiteql(f\"\"\"\n                SELECT t.id, t.tranid, t.status, t.trandate, t.shipdate\n                FROM transaction t\n                JOIN customer c ON c.id = t.entity\n                WHERE LOWER(c.email) = '{customer_email.replace(\"'\", \"''\")}'\n                  AND t.recordtype = 'salesorder'\n                  AND ROWNUM <= 5\n                ORDER BY t.trandate DESC\n            \"\"\")\n            if not rows:\n                return vapi_response(call_id,\n                    f\"I couldn't find any orders for the email address {customer_email}. \"\n                    \"Let me create a case for you so our team can look into this.\"\n                )\n            # Most recent order\n            row    = rows[0]\n            result = get_order_summary(row['id'])\n            if len(rows) > 1:\n                result = f\"You have {len(rows)} orders on file. Here's the most recent one: {result}\"\n            return vapi_response(call_id, result or 'I found your order but could not retrieve the details. I\\'ll have someone from our team follow up with you.')\n\n        else:\n            return vapi_response(call_id,\n                \"I need either an order number or the email address on the order to look it up. \"\n                \"Could you provide one of those?\"\n            )\n\n    except Exception as e:\n        app.logger.error(f'/lookup_order exception: {e}')\n        return vapi_response(call_id,\n            \"I ran into a technical issue looking up that order. Let me create a case so our team can follow up with you directly.\"\n        )\n\n\n@app.route('/create_case', methods=['POST'])\ndef create_case():\n    \"\"\"\n    Create a NetSuite support case from a phone call.\n    Input args: customer_name, phone, email (optional), issue_summary, callback_requested\n    \"\"\"\n    data  = request.get_json(force=True, silent=True) or {}\n    calls = parse_vapi_request(data)\n\n    if not calls:\n        call_id = data.get('tool_call_id', 'direct')\n        args    = data.get('parameters', data.get('arguments', data))\n        calls   = [(call_id, 'create_case', args)]\n\n    call_id, _, args = calls[0]\n\n    customer_name      = (args.get('customer_name') or 'Unknown Caller').strip()\n    phone              = (args.get('phone') or '').strip()\n    email              = (args.get('email') or '').strip()\n    issue_summary      = (args.get('issue_summary') or 'No details provided').strip()\n    callback_requested = args.get('callback_requested', True)\n\n    # Extract first name for personalized response\n    first_name = customer_name.split()[0] if customer_name and customer_name != 'Unknown Caller' else 'there'\n\n    try:\n        # Try to find the customer in NetSuite to link the case properly\n        company_id = CASE_COMPANY_ID  # default: Anonymous Rambo\n        if email:\n            cust = find_customer_by_email(email)\n            if cust:\n                company_id = str(cust['id'])\n        elif phone:\n            cust = find_customer_by_phone(phone)\n            if cust:\n                company_id = str(cust['id'])\n\n        # Build case title\n        case_title = f'Phone Call - {customer_name}'\n        if phone:\n            case_title += f' ({phone})'\n\n        # Build the incoming message body\n        msg_lines = [\n            f'Case created via Sam AI Phone Agent.',\n            f'',\n            f'Caller Name:  {customer_name}',\n        ]\n        if phone:\n            msg_lines.append(f'Phone:        {phone}')\n        if email:\n            msg_lines.append(f'Email:        {email}')\n        msg_lines += [\n            f'',\n            f'Issue Summary:',\n            f'{issue_summary}',\n            f'',\n            f'Callback Requested: {\"Yes\" if callback_requested else \"No\"}',\n        ]\n        incoming_message = '\\n'.join(msg_lines)\n\n        payload = {\n            'title':           case_title,\n            'status':          {'id': '1'},          # Not Started\n            'profile':         {'id': CASE_PROFILE_ID},\n            'company':         {'id': company_id},\n            'origin':          {'id': CASE_ORIGIN_PHONE},\n            'priority':        {'id': CASE_PRIORITY_ID},\n            'subsidiary':      {'id': CASE_SUBSIDIARY_ID},\n            'assigned':        {'id': AI_EMPLOYEE_ID},\n            'incomingMessage': incoming_message,\n            'phone':           phone,\n            'messageNew':      False,\n            'custevent2':      False,\n            'htmlMessage':     True,\n            'emailForm':       True,\n        }\n        if email:\n            payload['email'] = email\n\n        record_id, error = post_rec('supportCase', payload)\n\n        if record_id:\n            if callback_requested and phone:\n                result = (\n                    f\"Got it, {first_name}. I've created a case for you and someone from our customer service team \"\n                    f\"will call you back at {phone} within one business day. \"\n                    f\"Our office hours are Monday through Friday, 8:30 AM to 4:30 PM Central time. \"\n                    f\"Is there anything else I can help you with?\"\n                )\n            else:\n                result = (\n                    f\"Got it, {first_name}. I've created a support case and someone from our team will be in touch. \"\n                    f\"You can also reach us directly at 952-283-0777, Monday through Friday 8:30 AM to 4:30 PM Central. \"\n                    f\"Is there anything else I can help you with?\"\n                )\n            return vapi_response(call_id, result)\n        else:\n            app.logger.error(f'/create_case NS error: {error}')\n            return vapi_response(call_id,\n                f\"I wasn't able to create a case in our system right now, but please don't worry. \"\n                f\"You can call us directly at 952-283-0777 during business hours, Monday through Friday \"\n                f\"8:30 AM to 4:30 PM Central, and our team will be happy to help you.\"\n            )\n\n    except Exception as e:\n        app.logger.error(f'/create_case exception: {e}')\n        return vapi_response(call_id,\n            \"I ran into a technical issue. Please call us at 952-283-0777 and our team will assist you directly.\"\n        )\n\n\n@app.route('/lookup_customer', methods=['POST'])\ndef lookup_customer():\n    \"\"\"\n    Find a customer by email or phone and return a brief summary of\n    who they are, their recent orders, and any open support cases.\n    \"\"\"\n    data  = request.get_json(force=True, silent=True) or {}\n    calls = parse_vapi_request(data)\n\n    if not calls:\n        call_id = data.get('tool_call_id', 'direct')\n        args    = data.get('parameters', data.get('arguments', data))\n        calls   = [(call_id, 'lookup_customer', args)]\n\n    call_id, _, args = calls[0]\n\n    email = (args.get('email') or '').strip().lower()\n    phone = (args.get('phone') or '').strip()\n\n    try:\n        # \u2500\u2500 Find customer \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n        customer = None\n        if email:\n            customer = find_customer_by_email(email)\n        if not customer and phone:\n            customer = find_customer_by_phone(phone)\n\n        if not customer:\n            search_term = email or phone or 'that contact info'\n            return vapi_response(call_id,\n                f\"I wasn't able to find a customer in our system with {search_term}. \"\n                \"They may be a new customer, or we may have a different email or phone on file.\"\n            )\n\n        cust_id   = str(customer['id'])\n        full_name = ' '.join(filter(None, [customer.get('firstname'), customer.get('lastname')])) or 'Unknown'\n        cust_email = customer.get('email', '')\n        cust_phone = customer.get('phone', '')\n\n        # \u2500\u2500 Recent orders \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n        order_rows = run_suiteql(f\"\"\"\n            SELECT t.id, t.tranid, t.status, t.trandate, t.shipdate\n            FROM transaction t\n            WHERE t.entity = {cust_id}\n              AND t.recordtype = 'salesorder'\n              AND ROWNUM <= 3\n            ORDER BY t.trandate DESC\n        \"\"\")\n\n        # \u2500\u2500 Open support cases \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n        case_rows = run_suiteql(f\"\"\"\n            SELECT id, caseNumber, title, status\n            FROM supportCase\n            WHERE company = {cust_id}\n              AND status IN ('1','2','3','4')\n              AND ROWNUM <= 5\n        \"\"\")\n\n        # \u2500\u2500 Build summary \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n        parts = [f\"I found {full_name} in our system.\"]\n\n        if cust_email:\n            parts.append(f\"Email on file: {cust_email}.\")\n        if cust_phone:\n            parts.append(f\"Phone on file: {cust_phone}.\")\n\n        if order_rows:\n            latest = order_rows[0]\n            status_label = ORDER_STATUS_MAP.get(str(latest.get('status', '')), 'unknown status')\n            tran_id = latest.get('tranid', '?')\n            parts.append(\n                f\"Their most recent order is {tran_id}, placed on {format_date(str(latest.get('trandate', '')))}, \"\n                f\"currently {status_label}.\"\n            )\n            if len(order_rows) > 1:\n                parts.append(f\"They have {len(order_rows)} recent orders total.\")\n        else:\n            parts.append(\"No orders found in our system.\")\n\n        if case_rows:\n            open_count = len(case_rows)\n            parts.append(\n                f\"They have {open_count} open support case{'s' if open_count != 1 else ''}. \"\n                f\"Most recent: \\\"{case_rows[0].get('title', 'No title')}\\\".\"\n            )\n        else:\n            parts.append(\"No open support cases.\")\n\n        return vapi_response(call_id, ' '.join(parts))\n\n    except Exception as e:\n        app.logger.error(f'/lookup_customer exception: {e}')\n        return vapi_response(call_id,\n            \"I ran into a technical issue looking up that customer. \"\n            \"Please proceed with the call and I can create a case if needed.\"\n        )\n\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# /search_cases \u2014 Keyword search across 39,971 historical support case titles\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nimport os as _os\n\n_CASES_INDEX = []\n_CASES_FILE = _os.path.join(_os.path.dirname(_os.path.abspath(__file__)), 'rambo_all_cases.json')\n\n\ndef _load_cases():\n    global _CASES_INDEX\n    if not _CASES_INDEX:\n        try:\n            with open(_CASES_FILE, 'r') as f:\n                _CASES_INDEX = json.load(f)\n            app.logger.info(f\"Loaded {len(_CASES_INDEX):,} cases into search index.\")\n        except Exception as e:\n            app.logger.error(f\"Failed to load cases index: {e}\")\n            _CASES_INDEX = []\n\n\ndef _search_titles(keywords, cases, require_all=True):\n    results = []\n    for c in cases:\n        title = (c.get('title') or '').lower()\n        if require_all:\n            if all(kw in title for kw in keywords):\n                results.append(c)\n        else:\n            if any(kw in title for kw in keywords):\n                results.append(c)\n    return results\n\n\n@app.route('/search_cases', methods=['POST'])\ndef search_cases():\n    data       = request.get_json(force=True) or {}\n    message    = data.get('message', {})\n    tool_calls = message.get('toolCallList') or message.get('tool_calls') or []\n    call_id    = tool_calls[0]['id'] if tool_calls else 'direct'\n    args       = tool_calls[0].get('arguments', {}) if tool_calls else data\n\n    query = str(args.get('query', '')).strip()\n    limit = min(int(args.get('limit', 5)), 10)\n\n    if not query:\n        return vapi_response(call_id, \"No search query provided.\")\n\n    _load_cases()\n    if not _CASES_INDEX:\n        return vapi_response(call_id, \"Case search is temporarily unavailable.\")\n\n    keywords = [w for w in query.lower().split() if len(w) > 2]\n\n    # Strategy 1: AND all keywords\n    results = _search_titles(keywords, _CASES_INDEX, require_all=True)\n\n    # Strategy 2: model keyword + any issue word\n    if len(results) < 3 and len(keywords) >= 2:\n        model_kw  = keywords[:1]\n        issue_kws = keywords[1:]\n        results = [\n            c for c in _CASES_INDEX\n            if all(kw in (c.get('title') or '').lower() for kw in model_kw)\n            and any(kw in (c.get('title') or '').lower() for kw in issue_kws)\n        ]\n\n    # Strategy 3: OR fallback\n    if len(results) < 3:\n        results = _search_titles(keywords, _CASES_INDEX, require_all=False)\n\n    def _parse_date(c):\n        try:\n            return datetime.strptime(c.get('datecreated', '1/1/2000'), '%m/%d/%Y')\n        except Exception:\n            return datetime(2000, 1, 1)\n\n    results.sort(key=_parse_date, reverse=True)\n    top = results[:limit]\n\n    if not top:\n        return vapi_response(call_id,\n            \"No historical cases found matching that issue. Proceed with your product knowledge.\"\n        )\n\n    lines = [f\"Found {len(results)} similar past cases. Top {len(top)}:\"]\n    for i, c in enumerate(top, 1):\n        lines.append(\n            f\"{i}. Case ID {c['id']} \u2014 {c['casenumber']}: \\\"{c['title']}\\\" ({c['datecreated']})\"\n        )\n    lines.append(\"Call get_case_thread with a case id to read the full resolution.\")\n\n    return vapi_response(call_id, ' | '.join(lines))\n\n\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# /get_case_thread \u2014 Fetch full message thread for a specific case from NetSuite\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n@app.route('/get_case_thread', methods=['POST'])\ndef get_case_thread():\n    data       = request.get_json(force=True) or {}\n    message    = data.get('message', {})\n    tool_calls = message.get('toolCallList') or message.get('tool_calls') or []\n    call_id    = tool_calls[0]['id'] if tool_calls else 'direct'\n    args       = tool_calls[0].get('arguments', {}) if tool_calls else data\n\n    case_id = str(args.get('case_id', '')).strip()\n    if not case_id:\n        return vapi_response(call_id, \"No case ID provided.\")\n\n    try:\n        url  = f\"{BASE_URL}/supportCase/{case_id}\"\n        auth = make_auth_header('GET', url)\n        resp = requests.get(\n            url,\n            headers={'Authorization': auth, 'Content-Type': 'application/json'},\n            timeout=10\n        )\n\n        if resp.status_code == 404:\n            return vapi_response(call_id, f\"Case {case_id} not found in NetSuite.\")\n\n        rec    = resp.json()\n        title  = rec.get('title', 'No title')\n        thread = (rec.get('incomingMessage') or '').strip()\n        status = rec.get('status', {})\n        status_label = status.get('refName', 'unknown') if isinstance(status, dict) else str(status)\n\n        thread_preview = thread[:600]\n        if len(thread) > 600:\n            thread_preview += '...'\n\n        if thread_preview:\n            return vapi_response(call_id,\n                f\"Case {case_id}: \\\"{title}\\\" (status: {status_label}). \"\n                f\"Thread: {thread_preview}\"\n            )\n        else:\n            return vapi_response(call_id,\n                f\"Case {case_id}: \\\"{title}\\\" (status: {status_label}). No message body available.\"\n            )\n\n    except Exception as e:\n        app.logger.error(f'/get_case_thread exception: {e}')\n        return vapi_response(call_id,\n            \"I had trouble fetching that case thread. Proceed with available knowledge.\"\n        )\n\n\n\n\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# Main\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# /check_stock \u2014 Query NetSuite Transfer Orders for inbound container arrivals\n# \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n# Maps common spoken product names \u2192 item ID fragments used in NetSuite\nSTOCK_ALIASES = {\n    'HELLCAT':   ['HEL', 'HELLCAT'],\n    'KRUSADER':  ['KRU', 'KRUSADER'],\n    'REBEL':     ['RBL', 'REBEL'],\n    'MEGATRON':  ['MEG', 'MEGATRON'],\n    'PURSUIT':   ['PUR', 'PURSUIT'],\n    'BUSHWACKER':['BWK', 'BUSH'],\n    'RAMBLER':   ['RMB', 'RAMBLER'],\n}\n\n@app.route('/check_stock', methods=['POST'])\ndef check_stock():\n    data  = request.get_json(force=True, silent=True) or {}\n    calls = parse_vapi_request(data)\n    if not calls:\n        call_id = data.get('tool_call_id', 'direct')\n        args    = data.get('parameters', data.get('arguments', data))\n        calls   = [(call_id, 'check_stock', args)]\n    call_id, _, args = calls[0]\n\n    item_keyword = (args.get('item_keyword') or '').strip()\n    if not item_keyword:\n        return vapi_response(call_id, \"What product are you asking about?\")\n\n    kw = item_keyword.upper()\n    search_terms = STOCK_ALIASES.get(kw, [kw])\n\n    # Build OR clauses for itemid and displayname\n    id_conds = ' OR '.join([f\"UPPER(i.itemid) LIKE '%{t}%'\" for t in search_terms])\n    dn_conds = ' OR '.join([f\"UPPER(i.displayname) LIKE '%{t}%'\" for t in search_terms])\n\n    try:\n        rows = run_suiteql(f\"\"\"\n            SELECT i.itemid, i.displayname, tl.quantity, tl.expectedreceiptdate AS eta\n            FROM transaction t\n            JOIN transactionLine tl ON tl.transaction = t.id\n            JOIN item i ON i.id = tl.item\n            WHERE t.recordtype = 'transferorder'\n              AND t.status NOT IN ('transferOrder_closed', 'transferOrder_cancelled')\n              AND ({id_conds} OR {dn_conds})\n              AND tl.quantity > 0\n              AND tl.expectedreceiptdate IS NOT NULL\n            ORDER BY tl.expectedreceiptdate ASC\n        \"\"\")\n\n        from datetime import datetime as _dt\n        today = _dt.today()\n\n        # Filter to complete bikes (not parts) and future dates only\n        # Parts have RP-, RW- prefixes; bikes have model-based IDs\n        future = []\n        for r in rows:\n            itemid = r.get('itemid', '')\n            if itemid.startswith('RP-') or itemid.startswith('RW-'):\n                continue\n            eta_str = r.get('eta', '')\n            try:\n                eta_dt = _dt.strptime(eta_str, '%m/%d/%Y')\n                if eta_dt >= today:\n                    future.append((eta_dt, eta_str, r.get('displayname', itemid)))\n            except Exception:\n                pass\n\n        future.sort(key=lambda x: x[0])\n\n        if not future:\n            return vapi_response(call_id,\n                f\"I checked our inbound shipments and don't have a confirmed restock date for \"\n                f\"the {item_keyword} right now. I'd like to make sure someone follows up with you \u2014 \"\n                f\"can I get your name?\"\n            )\n\n        # Group by date, deduplicate\n        seen = {}\n        for eta_dt, eta_str, display in future:\n            if eta_str not in seen:\n                seen[eta_str] = []\n            seen[eta_str].append(display)\n\n        # Format the date nicely for speech (no abbreviations)\n        def fmt_date(s):\n            try:\n                d = _dt.strptime(s, '%m/%d/%Y')\n                # e.g. \"June 20th, 2026\"\n                day = d.day\n                suffix = \"th\" if 11 <= day <= 13 else {1:\"st\",2:\"nd\",3:\"rd\"}.get(day % 10, \"th\")\n                return d.strftime(f\"%B {day}{suffix}, %Y\")\n            except Exception:\n                return s\n\n        dates = list(seen.keys())[:2]\n        if len(dates) == 1:\n            result = (f\"Good news \u2014 the {item_keyword} is expected back in stock around \"\n                      f\"{fmt_date(dates[0])}.\")\n        else:\n            result = (f\"The {item_keyword} has shipments arriving around \"\n                      f\"{fmt_date(dates[0])} and {fmt_date(dates[1])}.\")\n\n        return vapi_response(call_id, result)\n\n    except Exception as e:\n        app.logger.error(f'/check_stock exception: {e}')\n        return vapi_response(call_id,\n            f\"I had a technical issue checking stock for the {item_keyword}. \"\n            f\"Let me get your info so someone can follow up \u2014 can I get your name?\"\n        )\n\n\nif __name__ == '__main__':\n    print(\"Starting Sam NetSuite Tools server on port 5055...\")\n    app.run(host='0.0.0.0', port=5055, debug=False)\n", "path": "/home/user/.workspace/sam_netsuite_tools.py"}